# app/jobs/process_brief_job.rb\n\nclass ProcessBriefJob < ApplicationJob\n  queue_as :default\n\n  def perform(brief_id)\n    brief = Brief.find_by(id: brief_id)\n    return unless brief\n\n    # Use the OpenAI service to process the brief\n    processor = OpenAIBriefProcessor.new(brief)\n    structured_data = processor.process\n\n    # Update the brief with the structured data\n    brief.update!(structured_data: structured_data, status: \'processed\')\n\n    # After processing, trigger Jira ticket creation\n    CreateJiraTicketsJob.perform_later(brief.id)\n  rescue StandardError => e\n    brief.update!(status: \'failed\')\n    Rails.logger.error(\"Error processing brief \#{brief_id}: \#{e.message}\")\n  end\nend